nd='.intval($kind))->order('id desc')->select();    }    return $cates;}/** * 按逗号把字符组成数组操作 * @param $str * @param $model * @param $names * @return string */function commaSplit($str,$model,$ids,$names){    $course_target = explode(',',$str);    $name = '';    foreach($course_target as $id){        $name .= $model->where(array($ids=>$id))->getField($names).',';    }    return substr($name,0,-1);}/** * QQ 邮箱发送邮件 */function sendMail($to,$title,$content){	vendor("PHPMailer.PHPMailerAutoload");	try {		$mail = new \PHPMailer(true);		$mail->IsSMTP();		$mail->SMTPSecure = 'ssl';		$mail->CharSet = 'UTF-8';		$mail->SMTPAuth = true; //开启认证		$mail->Port = 465; //网易为25		$mail->Host = "smtp.qq.com";		$mail->Username = "1069385609"; //qq此处为邮箱前缀名 163为邮箱名		$mail->Password = "";// 获取邮箱的安全码		$mail->AddReplyTo("1069385609@qq.com", "1069385609@qq.com");//回复地址		$mail->From = "1069385609@qq.com";		$mail->FromName = $title;		$mail->AddAddress($to);		$mail->Subject = $title;		$mail->Body = $content;		$mail->AltBody = "To view the message, please use an HTML compatible email viewer!"; //当邮件不支持html时备用显示		$mail->WordWrap = 80; // 设置每行字符串的长度		$mail->IsHTML(true);		$mail->Send();	} catch (phpmailerException $e) {	}}/** * 判断复选框是否被选中 * @param $str * @param $target */function checkedFlag($str,$model,$id){    $target = $model->order('sort_order desc')->select();    foreach($target as $k=>$v) {        $arr =explode(',',$str);        if( in_array($v[$id],$arr)){            $target[$k]['checked'] = 1;        }    }    return $target;}